" autocomplete="off" required>                            <label class="btn btn-outline-primary w-100" for="slot-<?= $i ?>">                                <?= $start->format('h:i A') ?>                            </label>                        </label>                    </div>                <?php endforeach; ?>            </div>                        <button type="submit" class="btn btn-primary w-100">Book Appointment</button>        </form>        </div>        @endif    </div></div></section> @endsection